import{o as t,c as r,D as s}from"./framework.2deede19.js";const n='{"title":"Панчакшара мантра","description":"","frontmatter":{"title":"Панчакшара мантра","subtitle":"Пятислоговая мантра","sans":"पञ्चक्षरमन्त्र","trans":"pañcakṣaramantra","tags":"mantra","date":"2021-04-05T00:00:00.000Z"},"headers":[{"level":3,"title":"Основные толкования:","slug":"основные-тоnкования"}],"relativePath":"mantra/panchakshara/index.md","lastUpdated":1625172014889}',a={},o=s('<hr><p class="sans big">ॐ नमः शिवाय</p><p class="trans">om namah śivāya</p><p>Поклонение Благому</p><div class="stanza"><h3 id="основные-тоnкования"><a class="header-anchor" href="#основные-тоnкования" aria-hidden="true">#</a> Основные толкования:</h3><ul><li><strong>Толкование джняни</strong>. Слово «<strong>намах</strong>» (नमः) обозначает ограниченную человеческую душу (дживу, जिव). Слово «<strong>шива</strong>» (शिव) обозначает Мировой Дух (Параматман). Окончание «<strong>йа</strong>» (य) указывает на идентичность Дживы и Параматмана. Слог <strong>Ом</strong> (ॐ) символизирует разрушение <strong>Майи</strong> — иллюзии.</li><li><strong>Толкование бхакти</strong>. Слог «<strong>ом</strong>» (ॐ) означает «весь мир, живой и неживой». Слово «намах» (नमः) — это сокращение от «<strong>намама</strong>» (न मम) — «не мой», «не для меня». Слово «<strong>шивайа</strong>» (शिवाय) означает «для Шивы». Мантра в целом переводится так: весь этот мир, живой и неживой, принадлежит не мне, существует не для меня, а для Шивы.</li></ul><p class="eng">Хотя она и имеет прямой перевод — <strong>Поклонение Благому</strong>, — её основное значение заключается не в словах, а в звуках, её составляющих, которые, в свою очередь, связываются с пятью перво-элементами (землёй, водой, огнём, воздухом и акашей) и ипостасью Шивы — <strong>Панчамукха</strong> или <strong>Панчанана</strong>([Обладающий] Пятью ликами).</p></div><hr>',6);a.render=function(s,n,a,e,g,l){return t(),r("div",null,[o])};export default a;export{n as __pageData};
